// Check if any new flows were analyzed since last check
const stats = $input.first().json;
const totalFlows = stats.total_flows || 0;
const anomalies = stats.total_anomalies || 0;
const anomalyRate = totalFlows > 0 ? (anomalies / totalFlows * 100) : 0;

return [{
  json: {
    total_flows: totalFlows,
    total_anomalies: anomalies,
    anomaly_rate: anomalyRate,
    avg_risk_score: stats.avg_risk_score || 0,
    attack_distribution: stats.attack_distribution || {},
    risk_distribution: stats.risk_distribution || {},
    has_data: totalFlows > 0,
    timestamp: new Date().toISOString()
  }
}];

// Extract file path from webhook body
const body = $input.first().json.body || $input.first().json;
const filePath = body.file_path || body.filePath || '';
const filename = filePath ? filePath.split('/').pop() : '';

if (!filePath) {
  throw new Error('No file_path provided in webhook body. Send: {"file_path": "/path/to/file.pcap"}');
}

return [{
  json: {
    file_path: filePath,
    filename: filename
  }
}];

// Process the upload response and check for threats
const result = $input.first().json;

const totalFlows = result.total_flows || 0;
const anomalyCount = result.anomaly_count || 0;
const avgRiskScore = result.avg_risk_score || 0;
const attackDist = result.attack_distribution || {};
const riskDist = result.risk_distribution || {};

const threatTypes = Object.entries(attackDist)
  .filter(([key]) => key.toUpperCase() !== 'BENIGN')
  .sort((a, b) => b[1] - a[1]);

const hasCriticalThreats = (riskDist.Critical || 0) > 0;
const hasHighThreats = (riskDist.High || 0) > 0;
const anomalyRate = totalFlows > 0 ? (anomalyCount / totalFlows * 100) : 0;

let severity = 'Low';
if (hasCriticalThreats) severity = 'Critical';
else if (hasHighThreats) severity = 'High';
else if (anomalyRate > 10) severity = 'Medium';

return [{
  json: {
    analysis_id: result.id,
    filename: result.filename,
    total_flows: totalFlows,
    anomaly_count: anomalyCount,
    anomaly_rate: anomalyRate,
    avg_risk_score: avgRiskScore,
    attack_distribution: attackDist,
    risk_distribution: riskDist,
    threat_types: threatTypes,
    has_threats: threatTypes.length > 0 || anomalyCount > 0,
    severity: severity,
    sample_flows: (result.sample_flows || []).slice(0, 5),
    timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;

let subject = `NetGuard: Threats found in ${data.filename}`;

let body = `# File Analysis Report\n\n`;
body += `**File:** ${data.filename}\n`;
body += `**Analysis ID:** ${data.analysis_id}\n`;
body += `**Time:** ${data.timestamp}\n\n`;

body += `## Summary\n`;
body += `- Total Flows: **${data.total_flows}**\n`;
body += `- Anomalies: **${data.anomaly_count}** (${data.anomaly_rate.toFixed(1)}%)\n`;
body += `- Avg Risk Score: **${data.avg_risk_score.toFixed(3)}**\n`;
body += `- Severity: **${data.severity}**\n\n`;

if (data.threat_types.length > 0) {
  body += `## Threat Breakdown\n`;
  for (const [type, count] of data.threat_types) {
    body += `- ${type}: ${count} flows\n`;
  }
  body += `\n`;
}

body += `## Risk Distribution\n`;
for (const [level, count] of Object.entries(data.risk_distribution)) {
  body += `- ${level}: ${count}\n`;
}

return [{ json: { subject, body, severity: data.severity, analysis_id: data.analysis_id } }];
